import React, { useState } from 'react';

const AboutPage = () => {
  // Dark Mode Logic
  const [isDarkMode, setIsDarkMode] = useState(false);
  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.body.classList.toggle('dark-mode');
  };

  // Gallery Rows (Tugma sa iyong HTML sequence)
  const row1 = ["ed6.png.jpg", "ed7.png.jpg", "ed8.png.jpg", "ed9.png.jpg", "ed10.png.jpg"];
  const row2 = ["ed18.png.jpg", "ed19.png.jpg", "ed20.png.jpg", "ed21.png.jpg", "ed22.png.jpg"];
  const row3 = ["ed11.png.jpg", "ed12.png.jpg", "ed2.png.jpg", "ed13.png.jpg", "ed14.png.jpg"];

  // Quiz State
  const [currentIdx, setCurrentIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [quizDone, setQuizDone] = useState(false);

  return (
    <main className="about-page">
      <div className="theme-toggle">
        <button onClick={toggleDarkMode}>{isDarkMode ? '☀️' : '🌙'}</button>
      </div>

      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
        <p>I use the lens as a mirror to catch the light I often forget I carry...</p>
      </section>

      {/* Row 1 - Magkakatabi at Pantay */}
      <div className="gallery-row">
        {row1.map((img, i) => (
          <div className="white-card" key={i}>
            <img src={`/photos/${img}`} alt="Personal" />
          </div>
        ))}
      </div>

      {/* Row 2 - Magkakatabi at Pantay */}
      <div className="gallery-row">
        {row2.map((img, i) => (
          <div className="white-card" key={i}>
            <img src={`/photos/${img}`} alt="Personal" />
          </div>
        ))}
      </div>

      <section className="hero">
        <h1>The Curator of Collective Growth</h1>
      </section>

      {/* Row 3 - Magkakatabi at Pantay */}
      <div className="gallery-row">
        {row3.map((img, i) => (
          <div className="white-card" key={i}>
            <img src={`/photos/${img}`} alt="Growth" />
          </div>
        ))}
      </div>

      {/* Quiz Section (Simplified placeholder) */}
      {!quizDone && (
        <section className="quiz-section">
           {/* Ang quiz logic mo dito... */}
        </section>
      )}
    </main>
  );
};

export default AboutPage;
